  {question:"Was ist die Pubertät?",options:["Kindheit","Phase der körperlichen und geistigen Reifung im Jugendalter","Alter","Schwangerschaft"],correct:1,explanation:"Pubertät: Wachstum, Hormonveränderungen, Reifung zum Erwachsenen.",topic:"Entwicklung"},
  {question:"Was sind Hormone?",options:["Vitamine","Chemische Botenstoffe die Körperfunktionen steuern","Nährstoffe","Nervenzellen"],correct:1,explanation:"Hormone: Adrenalin, Insulin, Östrogen – steuern Wachstum, Stoffwechsel, Stimmung.",topic:"Hormonsystem"},
  {question:"Was ist Insulin?",options:["Verdauungsenzym","Hormon das den Blutzucker reguliert","Vitamin","Antibiotikum"],correct:1,explanation:"Insulin: von der Bauchspeicheldrüse produziert – senkt Blutzucker.",topic:"Hormonsystem"},
  {question:"Was ist Diabetes?",options:["Knochenkrankheit","Stoffwechselerkrankung mit zu hohem Blutzucker","Lungenerkrankung","Herzerkrankung"],correct:1,explanation:"Diabetes: Körper kann Blutzucker nicht regulieren (fehlendes Insulin).",topic:"Krankheiten"},
  {question:"Was ist eine Sehne?",options:["Nerv","Verbindungsgewebe zwischen Muskel und Knochen","Gelenk","Blutgefäß"],correct:1,explanation:"Sehnen: verbinden Muskeln mit Knochen.",topic:"Körperbau"},
  {question:"Was ist Kalzium wichtig für?",options:["Muskeln","Knochen und Zähne","Blut","Nerven"],correct:1,explanation:"Kalzium: stärkt Knochen und Zähne.",topic:"Nährstoffe"},
  {question:"Was ist Vitamin C?",options:["Mineral","Vitamin das Immunsystem stärkt und in Obst vorkommt","Fett","Kohlenhydrat"],correct:1,explanation:"Vitamin C: in Zitrusfrüchten, stärkt Immunsystem, verhindert Skorbut.",topic:"Vitamine"},
  {question:"Was macht das Immunsystem?",options:["Blut pumpen","Körper gegen Krankheitserreger verteidigen","Nahrung verdauen","Knochen stärken"],correct:1,explanation:"Immunsystem: Abwehr von Viren, Bakterien, Pilzen.",topic:"Immunsystem"},
  {question:"Was ist eine Impfung?",options:["Medikament gegen Bakterien","Einführung abgeschwächter Erreger um Immunsystem zu trainieren","Operation","Diät"],correct:1,explanation:"Impfung: trainiert das Immunsystem vorab – Schutz gegen echte Infektion.",topic:"Immunsystem"},
  {question:"Was ist der Unterschied Viren/Bakterien?",options:["Kein Unterschied","Viren sind kleiner und brauchen Wirt zum Vermehren; Bakterien sind eigenständige Zellen","Viren sind größer","Bakterien brauchen Wirt"],correct:1,explanation:"Viren: kleiner, brauchen lebende Zelle. Bakterien: eigenständige Organismen.",topic:"Krankheitserreger"},
  {question:"Was ist ein Antibiotikum?",options:["Medikament gegen Viren","Medikament gegen Bakterien","Vitamin","Impfstoff"],correct:1,explanation:"Antibiotika: töten oder hemmen Bakterien. Gegen Viren wirkungslos!",topic:"Medizin"},
  {question:"Was ist ein gesunder Lebensstil?",options:["Viel sitzen","Ausgewogene Ernährung, Sport, Schlaf und kein Rauchen","Nur Sport","Nur gutes Essen"],correct:1,explanation:"Gesunder Lebensstil: Bewegung, ausgewogene Ernährung, ausreichend Schlaf.",topic:"Gesundheit"},
  {question:"Was tut das Zwerchfell?",options:["Pumpt Blut","Trennmuskel zwischen Brust und Bauch der beim Atmen hilft","Verdaut Nahrung","Filtert Blut"],correct:1,explanation:"Zwerchfell: Hauptmuskel der Atmung – senkt sich beim Einatmen.",topic:"Atmung"},
  {question:"Was ist der Herzschlag?",options:["Nervensignal","Zusammenziehen des Herzens das Blut pumpt","Lungenbewegung","Magenbewegung"],correct:1,explanation:"Herzschlag: Systole (Kontraktion) und Diastole (Entspannung) – ca. 70/min.",topic:"Herz"},
  {question:"Was ist Bluthochdruck?",options:["Zu niedriger Blutdruck","Dauerhaft erhöhter Druck in den Blutgefäßen – Risikofaktor für Herzinfarkt","Blutarmut","Zuckerkrankheit"],correct:1,explanation:"Bluthochdruck: belastet Herz und Gefäße – Risiko für Herzinfarkt/Schlaganfall.",topic:"Krankheiten"},
  {question:"Was sind Kohlenhydrate?",options:["Fette","Nährstoffe die schnell Energie liefern (Brot, Nudeln, Zucker)","Proteine","Vitamine"],correct:1,explanation:"Kohlenhydrate: wichtigste Energiequelle. In Brot, Nudeln, Zucker, Obst.",topic:"Ernährung"},
  {question:"Was sind Proteine?",options:["Kohlenhydrate","Nährstoffe aus Aminosäuren – Bausteine für Zellen, Muskeln, Enzyme","Fette","Vitamine"],correct:1,explanation:"Proteine: in Fleisch, Fisch, Hülsenfrüchten – Bausteine des Körpers.",topic:"Ernährung"},
  {question:"Was ist das zentrale Nervensystem?",options:["Nur das Gehirn","Gehirn und Rückenmark als Steuerzentrale des Körpers","Alle Nerven im Körper","Nur das Rückenmark"],correct:1,explanation:"ZNS = Gehirn + Rückenmark – Steuerung aller Körperfunktionen.",topic:"Nervensystem"},
  {question:"Was ist der Tastsinn?",options:["Sehen","Fühlen durch Hautrezeptoren (Druck, Wärme, Schmerz)","Hören","Riechen"],correct:1,explanation:"Tastsinn: Hautrezeptoren nehmen Berührung, Temperatur und Schmerz wahr.",topic:"Sinnesorgane"},
  {question:"Was ist der Sehvorgang?",options:["Licht geht durch Ohr","Licht trifft Netzhaut im Auge, Signal geht an Gehirn","Licht geht durch Haut","Licht wird reflektiert"],correct:1,explanation:"Auge: Linse fokussiert Licht auf Netzhaut → Nervensignal → Gehirn.",topic:"Sinnesorgane"},
  {question:"Was macht die Bauchspeicheldrüse?",options:["Pumpt Blut","Produziert Verdauungsenzyme und Insulin","Filtert Blut","Speichert Galle"],correct:1,explanation:"Bauchspeicheldrüse: Verdauungsenzyme in Darm + Insulin ins Blut.",topic:"Organe"},
  {question:"Was ist ein Knochenbruch?",options:["Muskelriss","Bruch eines Knochens durch zu starke Krafteinwirkung","Gelenkverletzung","Nervenschaden"],correct:1,explanation:"Knochenbruch: Knochen reißt – heilt in 6–8 Wochen nach Ruhigstellung.",topic:"Verletzungen"},
  {question:"Was ist Ernährungsumstellung?",options:["Sport","Andere Zusammensetzung der täglichen Kost um gesünder zu leben","Impfung","Schlaf"],correct:1,explanation:"Ernährungsumstellung: z.B. weniger Zucker, mehr Gemüse für gesünderes Leben.",topic:"Gesundheit"},
  {question:"Was ist die Wirbelsäule?",options:["Ein einziger Knochen","Kette aus Wirbeln die Rücken stützt und Rückenmark schützt","Schulterblatt","Hüftknochen"],correct:1,explanation:"Wirbelsäule: 33-34 Wirbel, Stütze und Schutz des Rückenmarks.",topic:"Körperbau"}
